package com.trademaster.ims.mobile.support.dto;
import jakarta.validation.constraints.*;import java.time.Instant;import java.util.List;
public final class SupportDtos{private SupportDtos(){}public record TicketSummary(String ticketNumber,String subject,String category,String priority,String status,String relatedOrderNumber,Instant createdAt,Instant updatedAt){}public record TicketDetail(String ticketNumber,String subject,String category,String priority,String status,String relatedOrderNumber,Instant createdAt,Instant updatedAt,List<TicketMessage>messages){}public record TicketMessage(String senderType,String message,Instant createdAt){}public record CreateTicketRequest(@NotBlank @Size(max=160)String subject,@NotBlank String category,String priority,@Size(max=60)String relatedOrderNumber,@NotBlank @Size(max=1500)String message){}public record AddMessageRequest(@NotBlank @Size(max=1500)String message){} }